pub mod kernel;
#[allow(unused_imports)]
pub use kernel::*;
#[tauri::command]

pub async fn get_runtime_config() -> CmdResult<Option<Mapping>> {
    Ok(Config::runtime().await.latest_arc().config.clone())
}

#[tauri::command]
pub async fn get_runtime_yaml() -> CmdResult<String> {
    let runtime = Config::runtime().await;
    let runtime = runtime.latest_arc();

    let config = runtime.config.as_ref();
    config
        .ok_or_else(|| anyhow!("failed to parse config to yaml file"))
        .and_then(|config| {
            serde_yaml_ng::to_string(config)
                .context("failed to convert config to yaml")
                .map(|s| s.into())
        })
        .stringify_err()
}

#[tauri::command]
pub async fn get_runtime_version() -> CmdResult<MihomoVersion> {
    crate::core::runtime_snapshot::read_runtime_version()
        .await
        .stringify_err()
}

#[tauri::command]
pub async fn get_runtime_base_config() -> CmdResult<BaseConfig> {
    crate::core::runtime_snapshot::read_runtime_base_config()
        .await
        .stringify_err()
}

#[tauri::command]
pub async fn patch_runtime_base_config(data: serde_json::Value) -> CmdResult<()> {
    let patch_value = serde_yaml_ng::to_value(data)
        .context("failed to convert base config patch to yaml")
        .stringify_err()?;
    let patch = patch_value
        .as_mapping()
        .cloned()
        .ok_or_else(|| anyhow!("base config patch must be a mapping"))
        .stringify_err()?;

    let result = crate::app::config::patch_clash(&patch).await;
    crate::core::runtime_snapshot::record_and_persist_runtime_lifecycle_event(
        "patch_runtime_base_config",
        result.is_ok(),
        result.as_ref().err().map(ToString::to_string),
        Some(format!("keys={}", patch.len())),
    );
    result.stringify_err()
}
#[tauri::command]
pub async fn update_runtime_geo() -> CmdResult<()> {
    let result = crate::core::runtime_bridge::update_runtime_geo().await;
    crate::core::runtime_snapshot::record_and_persist_runtime_lifecycle_event(
        LIFECYCLE_UPDATE_GEO,
        result.is_ok(),
        result.as_ref().err().map(ToString::to_string),
        None,
    );
    result.stringify_err()
}
